    accumulated_depreciation_2019 = next(item['number_value'] for item in value_list if item['category'] == 'Accumulated depreciation' and item['header1'] == '2019')
    change = accumulated_depreciation_2019 - accumulated_depreciation_2018
    return (round(change, 2), 'million')

def run(value_list):
    # Filter for currency translation differences in financial assets
    for item in value_list:
        if item['category'] == 'Currency translation differences' and item['header3'] == 'Financial assets':
            value_2019 = item['number_value']
            break
    else:
        value_2019 = 0.0

    for item in value_list:
        if item['category'] == 'Currency translation differences' and item['header3'] == 'Financial assets':
            value_2018 = item['number_value']
            break
    else:
        value_2018 = 0.0

    change = value_2019 - value_2018
    return (round(change, 2), 'million')

def run(value_list):
    # Filter for weighted average hedged rate for the year
    weighted_avg_2018 = next((item['number_value'] for item in value_list if item['category'] == 'Weighted average hedged rate for the year' and item['header5'] == '2018'), None)
    weighted_avg_2019 = next((item['number_value'] for item in value_list if item['category'] == 'Weighted average hedged rate for the year' and item['header5'] == '2019'), None)

    # Calculate percentage change
    if weighted_avg_2018 is not None and weighted_avg_2019 is not None:
        percentage_change = ((weighted_avg_2019 - weighted_avg_2018) / weighted_avg_2018) * 100
        return (round(percentage_change, 2), 'percent')
    else:
        return (0.0, '')

def run(value_list):
    total_revenue_2019 = 0
    taiwan_revenue_2019 = 0
    japan_revenue_2019 = 0

    for item in value_list:
        if item['header1'] == '2019' and item['header2'] == 'For the year ended':
            total_revenue_2019 += item['number_value']
            if item['category'] == 'Taiwan':
                taiwan_revenue_2019 = item['number_value']
            elif item['category'] == 'Japan':
                japan_revenue_2019 = item['number_value']

    total_revenue_taiwan_japan_2019 = taiwan_revenue_2019 + japan_revenue_2019
    percentage = (total_revenue_taiwan_japan_2019 / total_revenue_2019) * 100

    return (round(percentage, 2), 'percent')

