        if item['header1'] == '2019' and item['category'] == 'Net income':
            return (round(item['number_value'], 2), '')

def run(value_list):
    total_goodwill_2018 = next((item['number_value'] for item in value_list if item['category'] == 'Goodwill acquired' and item['header1'] == 'Network Software & Systems'), 0)
    total_goodwill_2019 = next((item['number_value'] for item in value_list if item['category'] == 'Goodwill acquired' and item['header1'] == 'Network Software & Systems'), 0)
    total_goodwill = total_goodwill_2018 + total_goodwill_2019
    return (total_goodwill, '')

def run(value_list):
    total_long_term_debt = 0
    payments_due_5_years_or_below = 0

    for item in value_list:
        if item['category'] == 'Long-term debt .':
            if item['header1'] == 'Total':
                total_long_term_debt = item['number_value']
            elif item['header2'] == 'Payments Due by Period (in millions)' and item['header3'] == 'Contractual Obligations':
                if item['header1'] in ['1-3 Years', '3-5 Years', 'Less than 1 Year']:
                    payments_due_5_years_or_below += item['number_value']

    proportion = payments_due_5_years_or_below / total_long_term_debt
    return (round(proportion, 2), 'million')

def run(value_list):
    non_vested_2018_shares = next(item['number_value'] for item in value_list if item['category'] == 'Non-vested at December 31, 2018' and item['header1'] == 'Shares')
    granted_shares = next(item['number_value'] for item in value_list if item['category'] == 'Granted' and item['header1'] == 'Shares')
    non_vested_2019_shares = next(item['number_value'] for item in value_list if item['category'] == 'Non-vested at December 31, 2019' and item['header1'] == 'Shares')

    percentage = (granted_shares / non_vested_2019_shares) * 100
    return (round(percentage, 2), '')

def run(value_list):
    non_vested_2019_shares = next(v['number_value'] for v in value_list if v['category'] == 'Non-vested at December 31, 2019' and v['header1'] == 'Shares')
    forfeited_shares = next(v['number_value'] for v in value_list if v['category'] == 'Forfeited' and v['header1'] == 'Shares')
    total_non_vested_2019_shares = non_vested_2019_shares
    percentage_forfeited = (forfeited_shares / total_non_vested_2019_shares) * 100
    return (round(percentage_forfeited, 2), '')
